// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract PostingBoard {
    // 1. define a public postCount
    uint256 public postCount;

    // 2. define a public posts(uint256) getter for a struct
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    mapping(uint256 => Post) public posts;

    // 5. expose authorBalances(address)
    mapping(address => uint256) public authorBalances;

    // Helper event for transparency
    event PostCreated(uint256 indexed postId, address indexed author, string content);
    event PostBoosted(uint256 indexed postId, address indexed booster, uint256 amount);
    event Withdrawn(address indexed author, uint256 amount);

    // 3. expose createPost(string calldata content)
    function createPost(string calldata content) external returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");

        uint256 newPostId = ++postCount;

        posts[newPostId] = Post({
            author: msg.sender,
            content: content,
            totalPower: 0
        });

        emit PostCreated(newPostId, msg.sender, content);
        return newPostId;
    }

    // 4. expose boostPost(uint256 postId) payable
    function boostPost(uint256 postId) external payable {
        require(postId != 0 && postId <= postCount, "Invalid post ID");
        require(msg.value > 0, "Must send ETH to boost");

        Post storage post = posts[postId];
        address author = post.author;
        post.totalPower += msg.value;
        authorBalances[author] += msg.value;

        emit PostBoosted(postId, msg.sender, msg.value);
    }

    // 6. expose withdraw()
    function withdraw() external {
        uint256 balance = authorBalances[msg.sender];
        require(balance > 0, "No balance to withdraw");

        authorBalances[msg.sender] = 0;

        emit Withdrawn(msg.sender, balance);

        (bool success, ) = payable(msg.sender).call{value: balance}("");
        require(success, "Transfer failed");
    }
}
